echo "Temp: $(vcgencmd measure_temp | cut -d= -f2) | ARM: $(vcgencmd measure_clock arm | awk -F= '{printf "%.0f MHz", $2/1000000}') | Core: $(vcgencmd measure_clock core | awk -F= '{printf "%.0f MHz", $2/1000000}') | GPU V: $(vcgencmd measure_volts core | cut -d= -f2) | SDRAM_C V: $(vcgencmd measure_volts sdram_c | cut -d= -f2) | SDRAM_I V: $(vcgencmd measure_volts sdram_i | cut -d= -f2) | SDRAM_P V: $(vcgencmd measure_volts sdram_p | cut -d= -f2) | Throttle: $(vcgencmd get_throttled | cut -d= -f2) | Gov: $(cat /sys/devices/system/cpu/cpu0/cpufreq/scaling_governor) | CurFreq: $(cat /sys/devices/system/cpu/cpu0/cpufreq/scaling_cur_freq | awk '{printf "%.0f MHz", $1/1000}') | MinFreq: $(cat /sys/devices/system/cpu/cpu0/cpufreq/scaling_min_freq | awk '{printf "%.0f MHz", $1/1000}') | MaxFreq: $(cat /sys/devices/system/cpu/cpu0/cpufreq/scaling_max_freq | awk '{printf "%.0f MHz", $1/1000}') | GPU Mem: $(vcgencmd get_mem gpu | cut -d= -f2) | ARM Mem: $(vcgencmd get_mem arm | cut -d= -f2) | RAM Used: $(free -h | awk '/Mem:/ {print $3 "/" $2}') | Disk Used: $(df -h / | awk 'NR==2 {print $3 "/" $2}')"
